// ── HELPERS ───────────────────────────────────────────────────────────────────
function fmt(d){if(!d)return"—";const dt=new Date(d);return`${String(dt.getDate()).padStart(2,"0")}/${String(dt.getMonth()+1).padStart(2,"0")}/${dt.getFullYear()}`;}
function daysLeft(d){if(!d)return null;return Math.round((new Date(d)-new Date())/86400000);}
function daysBetween(a,b){return Math.max(1,Math.round((new Date(b)-new Date(a))/86400000));}

async function callClaude(prompt){
  try{
    const res=await fetch("/api/claude",{method:"POST",headers:{"Content-Type":"application/json"},
      body:JSON.stringify({prompt,system:"Tu es un assistant expert en gestion locative aux Antilles françaises. Tu génères des documents professionnels en français. Sois direct et professionnel."})});
    const d=await res.json();return d.content?.[0]?.text||"Erreur.";
  }catch{return"Erreur de connexion.";}
}

function Tag({label,color,bg}){return<span style={{fontSize:11,padding:"3px 10px",borderRadius:20,background:bg,color,fontFamily:"Fraunces,serif",fontStyle:"italic",whiteSpace:"nowrap"}}>{label}</span>;}

function Inp({label,value,onChange,type="text",required}){
  return(
    <div style={{display:"flex",flexDirection:"column",gap:5}}>
      <label style={{fontSize:11,color:T.inkMuted,fontFamily:"Fraunces,serif",fontStyle:"italic",letterSpacing:1}}>{label}{required?" *":""}</label>
      <input type={type} value={value||""} onChange={e=>onChange(e.target.value)}
        style={{background:T.white,border:`1px solid ${T.borderDark}`,borderRadius:9,padding:"10px 14px",color:T.ink,fontFamily:"Fraunces,serif",fontSize:13,outline:"none",width:"100%"}}/>
    </div>
  );
}

function AIModal({title,content,loading,onClose}){
  return(
    <div onClick={onClose} style={{position:"fixed",inset:0,background:"rgba(10,31,26,0.65)",zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center",padding:16,backdropFilter:"blur(6px)"}}>
      <div onClick={e=>e.stopPropagation()} style={{background:T.white,borderRadius:20,padding:"28px",maxWidth:580,width:"100%",maxHeight:"82vh",display:"flex",flexDirection:"column",boxShadow:"0 24px 80px rgba(0,0,0,0.25)"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:16}}>
          <div>
            <div style={{fontSize:10,letterSpacing:3,color:T.teal,textTransform:"uppercase",fontFamily:"Playfair Display,serif",marginBottom:4}}>IA · KazManager</div>
            <h3 style={{fontFamily:"Playfair Display,serif",color:T.ink,fontSize:17,margin:0}}>{title}</h3>
          </div>
          <button onClick={onClose} style={{background:"none",border:"none",color:T.inkMuted,fontSize:22,cursor:"pointer"}}>✕</button>
        </div>
        <div style={{flex:1,overflowY:"auto"}}>
          {loading
            ?<div style={{display:"flex",alignItems:"center",gap:10,color:T.teal,fontFamily:"Fraunces,serif",fontStyle:"italic"}}>
               <div className="spin" style={{width:18,height:18,border:`2px solid ${T.tealMid}`,borderTop:`2px solid ${T.teal}`,borderRadius:"50%"}}/>
               L'IA rédige…
             </div>
            :<pre style={{fontFamily:"Fraunces,serif",color:T.inkLight,fontSize:13,lineHeight:1.85,whiteSpace:"pre-wrap",margin:0}}>{content}</pre>}
        </div>
        {!loading&&content&&
          <div style={{display:"flex",gap:8,marginTop:16}}>
            <button onClick={()=>navigator.clipboard?.writeText(content)} style={{background:T.teal,color:"#fff",border:"none",borderRadius:9,padding:"10px 20px",cursor:"pointer",fontFamily:"Fraunces,serif",fontSize:13}}>📋 Copier</button>
            <button onClick={onClose} style={{background:T.cream,border:`1px solid ${T.border}`,color:T.inkMuted,borderRadius:9,padding:"10px 16px",cursor:"pointer",fontFamily:"Fraunces,serif",fontSize:13}}>Fermer</button>
          </div>}
      </div>
    </div>
  );
}

function FileUpload({label,value,onChange,accept="*"}){
  const ref=useRef();
  return(
    <div style={{display:"flex",flexDirection:"column",gap:5}}>
      <label style={{fontSize:11,color:T.inkMuted,fontFamily:"Fraunces,serif",fontStyle:"italic",letterSpacing:1}}>{label}</label>
      <div onClick={()=>ref.current.click()} style={{border:`1.5px dashed ${value?T.teal:T.borderDark}`,borderRadius:9,padding:"10px 14px",cursor:"pointer",display:"flex",alignItems:"center",gap:8,background:value?T.tealLight:T.cream}}>
        <span style={{fontSize:16}}>{value?"✅":"📎"}</span>
        <span style={{fontFamily:"Fraunces,serif",fontSize:12,color:value?T.teal:T.inkMuted}}>{value?value.name||"Fichier chargé":"Cliquer pour uploader"}</span>
        <input ref={ref} type="file" accept={accept} style={{display:"none"}} onChange={e=>onChange(e.target.files[0]||null)}/>
      </div>
    </div>
  );
}

function PhotoUpload({value,onChange,size=80}){
  const ref=useRef();
  return(
    <div onClick={()=>ref.current.click()} style={{width:size,height:size,borderRadius:"50%",border:`2px dashed ${T.borderDark}`,cursor:"pointer",overflow:"hidden",background:T.cream,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
      {value?<img src={value} alt="photo" style={{width:"100%",height:"100%",objectFit:"cover"}}/>:<span style={{fontSize:size/3}}>📷</span>}
      <input ref={ref} type="file" accept="image/*" style={{display:"none"}} onChange={e=>{
        const f=e.target.files[0];if(f){const r=new FileReader();r.onload=ev=>onChange(ev.target.result);r.readAsDataURL(f);}
      }}/>
    </div>
  );
}

function NotifBell({notifications,setNotifications}){
  const [open,setOpen]=useState(false);
  const unread=notifications.filter(n=>!n.read).length;
  return(
    <div style={{position:"relative"}}>
      <button onClick={()=>setOpen(o=>!o)} style={{background:"none",border:"none",cursor:"pointer",position:"relative",padding:6}}>
        <span style={{fontSize:20}}>🔔</span>
        {unread>0&&<div style={{position:"absolute",top:2,right:2,width:16,height:16,borderRadius:"50%",background:T.red,color:"#fff",fontSize:9,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:700}}>{unread}</div>}
      </button>
      {open&&(
        <div style={{position:"absolute",right:0,top:40,background:T.white,border:`1px solid ${T.border}`,borderRadius:14,padding:16,width:290,boxShadow:"0 8px 30px rgba(0,0,0,0.15)",zIndex:200}}>
          <div style={{display:"flex",justifyContent:"space-between",marginBottom:10}}>
            <div style={{fontFamily:"Playfair Display,serif",color:T.ink,fontSize:13}}>Notifications</div>
            <button onClick={()=>{setNotifications(ns=>ns.map(n=>({...n,read:true})));}} style={{background:"none",border:"none",color:T.teal,fontSize:11,cursor:"pointer",fontFamily:"Fraunces,serif"}}>Tout lire</button>
          </div>
          {notifications.length===0?<div style={{fontFamily:"Fraunces,serif",fontStyle:"italic",color:T.inkMuted,fontSize:12,textAlign:"center",padding:10}}>Aucune notification</div>
            :notifications.map(n=>(
              <div key={n.id} style={{padding:"8px 0",borderBottom:`1px solid ${T.border}`,opacity:n.read?0.5:1}}>
                <div style={{fontFamily:"Fraunces,serif",color:T.ink,fontSize:12}}>{n.message}</div>
                <div style={{color:T.inkMuted,fontSize:10,marginTop:2}}>{fmt(n.date)}</div>
              </div>
            ))}
        </div>
      )}
    </div>
  );
}


