function Login({onSuccess,IMG_LOGO_GOLD}){
  const [email,setEmail]=useState("");
  const [password,setPassword]=useState("");
  const [error,setError]=useState("");
  const submit=()=>{
    if(email===DEMO_USER.email&&password===DEMO_USER.password)onSuccess(DEMO_USER);
    else setError("Identifiants incorrects. Essayez demo@kazmanager.com / demo123");
  };
  return(
    <div style={{minHeight:"100vh",background:T.darkGreen,display:"flex",alignItems:"center",justifyContent:"center",padding:24}}>
      <div style={{background:T.white,borderRadius:24,padding:"40px 32px",maxWidth:420,width:"100%",boxShadow:"0 30px 80px rgba(0,0,0,0.3)"}}>
        <div style={{textAlign:"center",marginBottom:28}}>
          <img src={IMG_LOGO_GOLD} alt="logo" style={{width:160,height:"auto",marginBottom:12}}/>
          <div style={{fontFamily:"Fraunces,serif",fontStyle:"italic",color:T.inkMuted,fontSize:13}}>Connectez-vous à votre espace</div>
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:10,marginBottom:18}}>
          {[["🔵","Continuer avec Facebook"],["🔴","Continuer avec Google"]].map(([icon,label])=>(
            <button key={label} onClick={()=>onSuccess(DEMO_USER)}
              style={{width:"100%",background:T.cream,border:`1.5px solid ${T.border}`,borderRadius:11,padding:"12px",cursor:"pointer",fontFamily:"Fraunces,serif",fontSize:13,color:T.ink,display:"flex",alignItems:"center",justifyContent:"center",gap:10}}>
              <span style={{fontSize:18}}>{icon}</span>{label}
            </button>
          ))}
        </div>
        <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:16}}>
          <div style={{flex:1,height:1,background:T.border}}/>
          <span style={{fontFamily:"Fraunces,serif",fontStyle:"italic",color:T.inkMuted,fontSize:12}}>ou par email</span>
          <div style={{flex:1,height:1,background:T.border}}/>
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:12}}>
          <Inp label="Email" value={email} onChange={setEmail} type="email" required/>
          <Inp label="Mot de passe" value={password} onChange={setPassword} type="password" required/>
        </div>
        {error&&<div style={{background:T.redLight,borderRadius:9,padding:"10px 14px",color:T.red,fontSize:12,fontFamily:"Fraunces,serif",marginTop:10}}>{error}</div>}
        <button onClick={submit} style={{width:"100%",background:`linear-gradient(135deg,${T.teal},#0A6B5D)`,color:"#fff",border:"none",borderRadius:12,padding:14,cursor:"pointer",fontFamily:"Playfair Display,serif",fontSize:15,marginTop:16}}>
          Se connecter →
        </button>
        <div style={{textAlign:"center",marginTop:14,fontFamily:"Fraunces,serif",fontStyle:"italic",color:T.inkMuted,fontSize:11}}>Démo : demo@kazmanager.com / demo123</div>
      </div>
    </div>
  );
}

